const crypto = require('crypto');
const secret = process.env.WEBHOOK_HMAC_SECRET;
if (!secret) return [{ json: { ok: false, reason: 'WEBHOOK_HMAC_SECRET not configured' } }];
const signature = $input.first().json.$headers?.['x-adoff-signature'];
if (!signature) return [{ json: { ok: false, reason: 'missing_signature_header' } }];
const bodyRaw = $input.first().json.$body;
if (!bodyRaw) return [{ json: { ok: false, reason: 'empty_body' } }];
const expectedHmac = crypto.createHmac('sha256', Buffer.from(secret, 'hex')).update(bodyRaw, 'utf8').digest('hex');
try { crypto.timingSafeEqual(Buffer.from(signature, 'hex'), Buffer.from(expectedHmac, 'hex')); return [{ json: { ok: true, payload: JSON.parse(bodyRaw), timestamp: new Date().toISOString() } }]; } catch (err) { return [{ json: { ok: false, reason: 'invalid_signature', timestamp: new Date().toISOString() } }]; }

const isWebhook = $json.payload !== undefined;
if (isWebhook) {
  const p = $json.payload;
  return [{ json: { draft_id: p.draft_id, asset_type: p.asset_type || 'caption_social', platform: p.platform, lang: p.lang, concept: p.concept, caption_preview: p.caption_preview || '', source: 'webhook' } }];
} else {
  return $json.map(row => ({ json: { draft_id: row.id, asset_type: row.asset_type || 'caption_social', platform: row.platform, lang: row.lang, concept: row.concept, caption_preview: row.body || '', source: 'schedule' } }));
}

const resp = $input.first().json;
if (!resp || !resp.ok) return [{ json: { media_type: 'video', media_path: null, error: resp?.error || 'cyber-purge build failed', status: 'failed' } }];
const videoPath = resp.output?.video || resp.video_path || 'unknown';
return [{ json: { media_type: 'video', media_path: videoPath, dimensions: '1920x1080', status: 'generated', error: null } }];

const resp = $input.first().json;
if (!resp || !resp.job_id) return [{ json: { media_type: 'image', media_path: null, job_id: null, error: 'image-gen enqueue failed', status: 'pending' } }];
return [{ json: { media_type: 'image', media_path: null, job_id: resp.job_id, dimensions: '1080x1350', status: 'pending', error: null } }];

const resp = $input.first().json;
if (!resp || !resp.job_id) return [{ json: { media_type: 'image', media_path: null, job_id: null, error: 'image-gen enqueue failed', status: 'pending' } }];
return [{ json: { media_type: 'image', media_path: null, job_id: resp.job_id, dimensions: '1200x630', status: 'pending', error: null } }];

const resp = $input.first().json;
if (!resp || !resp.job_id) return [{ json: { media_type: 'image', media_path: null, job_id: null, error: 'image-gen enqueue failed', status: 'pending' } }];
return [{ json: { media_type: 'image', media_path: null, job_id: resp.job_id, dimensions: '1200x675', status: 'pending', error: null } }];

const resp = $input.first().json;
if (!resp || !resp.job_id) return [{ json: { media_type: 'image', media_path: null, job_id: null, error: 'image-gen enqueue failed', status: 'pending' } }];
return [{ json: { media_type: 'image', media_path: null, job_id: resp.job_id, dimensions: '1200x627', status: 'pending', error: null } }];

const original = $('normalize-input').first().json;
const media = $input.first().json;
return [{ json: { draft_id: original.draft_id, platform: original.platform, lang: original.lang, concept: original.concept, asset_type: original.asset_type, media_type: media.media_type, media_path: media.media_path, job_id: media.job_id, dimensions: media.dimensions, status: media.status, error: media.error, prompt_used: media.prompt_used, source: original.source } }];
